UPDATE requirement
function_name = #{functionName}, module_name = #{moduleName}, request_department = #{requestDepartment}, request_owner = #{requestOwner}, product_owner = #{productOwner}, priority = #{priority}, planned_start_time = #{plannedStartTime}, planned_end_time = #{plannedEndTime}, actual_start_time = #{actualStartTime}, actual_end_time = #{actualEndTime}, status = #{status}, description = #{description},
WHERE id = #{id}

