SELECT priority AS name, COUNT(*) AS value FROM requirement WHERE priority IS NOT NULL AND priority != ''
AND request_department = #{department}
GROUP BY priority

SELECT status AS name, COUNT(*) AS value FROM requirement
WHERE request_department = #{department}
GROUP BY status
